<script setup lang="ts">
import { computed, onMounted, reactive, ref } from "vue";
import type { MerchantApplicationStatus, MerchantApplicationView, UserRole } from "@moecraft/shared";
import { apiRequest } from "../api";

const props = defineProps<{ roles: UserRole[] }>();
const reviewer = computed(() => props.roles.some((role) => role.startsWith("PLATFORM_")));
const loading = ref(true);
const busy = ref(false);
const error = ref("");
const message = ref("");
const mine = ref<MerchantApplicationView | null>(null);
const queue = ref<MerchantApplicationView[]>([]);
const selected = ref<MerchantApplicationView | null>(null);
const comment = ref("");
const form = reactive({ companyName: "", contactName: "", contactPhone: "", contactEmail: "", businessLicenseNumber: "", qualificationFileIds: [] as string[], agreementAccepted: false });

const labels: Record<MerchantApplicationStatus, string> = { DRAFT: "草稿", SUBMITTED: "待审核", NEEDS_CHANGES: "待补件", APPROVED: "已通过", REJECTED: "已拒绝", WITHDRAWN: "已撤回" };
const reasonTemplates = ["资质文件不清晰，请重新上传", "企业信息与资质文件不一致", "缺少品牌或版权授权证明"];
const editable = computed(() => !mine.value || ["DRAFT", "NEEDS_CHANGES", "REJECTED", "WITHDRAWN"].includes(mine.value.status));
const submittedCount = computed(() => queue.value.filter((item) => item.status === "SUBMITTED").length);
const approvedCount = computed(() => queue.value.filter((item) => item.status === "APPROVED").length);

function copy(item: MerchantApplicationView) { Object.assign(form, { companyName: item.companyName, contactName: item.contactName, contactPhone: item.contactPhone, contactEmail: item.contactEmail, businessLicenseNumber: item.businessLicenseNumber, qualificationFileIds: [...item.qualificationFileIds], agreementAccepted: item.agreementAccepted }); }
function clearFeedback() { error.value = ""; message.value = ""; }
async function load() { loading.value = true; clearFeedback(); try { if (reviewer.value) queue.value = await apiRequest<MerchantApplicationView[]>("/merchant-applications"); else { mine.value = await apiRequest<MerchantApplicationView | null>("/merchant-applications/mine"); if (mine.value) copy(mine.value); } } catch { error.value = "加载失败，请确认 API 已启动。"; } finally { loading.value = false; } }
async function addFiles(files: FileList | null) { clearFeedback(); for (const file of Array.from(files ?? [])) { try { const asset = await apiRequest<{ id: string }>("/files", { method: "POST", body: JSON.stringify({ purpose: "merchant-qualification", fileName: file.name, mimeType: file.type, sizeBytes: file.size }) }); form.qualificationFileIds.push(asset.id); } catch { error.value = `${file.name} 的类型或大小不合规。`; } } }
async function save() { busy.value = true; clearFeedback(); try { mine.value = await apiRequest<MerchantApplicationView>("/merchant-applications/mine", { method: "PUT", body: JSON.stringify(form) }); copy(mine.value); message.value = "草稿已安全保存。"; } catch { error.value = "保存失败，请检查全部必填字段。"; } finally { busy.value = false; } }
async function applicantAction(action: "submit" | "withdraw") { busy.value = true; clearFeedback(); try { mine.value = await apiRequest<MerchantApplicationView>(`/merchant-applications/mine/${action}`, { method: "POST" }); message.value = action === "submit" ? "申请已提交，平台将尽快审核。" : "申请已撤回。"; } catch { error.value = "操作失败，请检查申请状态和资料完整性。"; } finally { busy.value = false; } }
async function review(decision: "APPROVE" | "REJECT" | "REQUEST_CHANGES") { if (!selected.value) return; busy.value = true; clearFeedback(); try { await apiRequest(`/merchant-applications/${selected.value.id}/review`, { method: "POST", body: JSON.stringify({ decision, comment: comment.value || undefined }) }); selected.value = null; comment.value = ""; message.value = "审核结果已保存并写入审计记录。"; await load(); } catch { error.value = "审核失败；拒绝或补件必须填写原因。"; } finally { busy.value = false; } }
async function merchantStatus(status: "ACTIVE" | "SUSPENDED") { if (!selected.value) return; busy.value = true; clearFeedback(); const id = selected.value.id; try { await apiRequest(`/merchant-applications/${id}/merchant-status`, { method: "POST", body: JSON.stringify({ status, reason: comment.value || "平台运营状态调整" }) }); message.value = status === "ACTIVE" ? "商家已恢复营业。" : "商家已停用。"; await load(); selected.value = queue.value.find((item) => item.id === id) ?? null; } catch { error.value = "商家状态调整失败。"; } finally { busy.value = false; } }
onMounted(load);
</script>

<template>
  <section class="onboarding content-scroll">
    <div class="page-shell">
      <header class="hero">
        <div class="hero-copy"><span class="eyebrow"><i /> MERCHANT CENTER</span><h1>{{ reviewer ? "商家入驻审核" : "开启你的创作商店" }}</h1><p>{{ reviewer ? "统一处理申请、资质与商家营业状态，让每次决策都有据可查。" : "提交品牌与经营资料，通过平台审核后即可发布商品、管理订单。" }}</p></div>
        <div v-if="reviewer" class="hero-metrics"><div><b>{{ submittedCount }}</b><span>待处理</span></div><div><b>{{ approvedCount }}</b><span>已通过</span></div></div>
        <div v-else class="hero-steps"><span class="done">1 <small>填写资料</small></span><i /><span :class="{ done: mine }">2 <small>平台审核</small></span><i /><span :class="{ done: mine?.status === 'APPROVED' }">3 <small>开店经营</small></span></div>
        <button class="icon-button" aria-label="刷新" title="刷新" @click="load">↻</button>
      </header>

      <transition name="toast"><p v-if="error || message" class="feedback" :class="error ? 'is-error' : 'is-success'" role="status"><span>{{ error ? "!" : "✓" }}</span>{{ error || message }}</p></transition>
      <div v-if="loading" class="loading-card"><span class="spinner" /><p>正在同步入驻信息…</p></div>

      <template v-else-if="reviewer">
        <div class="review-layout">
          <aside class="application-list">
            <div class="section-heading"><div><span>APPLICATIONS</span><h2>申请列表</h2></div><b>{{ queue.length }}</b></div>
            <div v-if="!queue.length" class="empty-state"><span>◇</span><b>暂时没有申请</b><p>新的商家申请会出现在这里。</p></div>
            <button v-for="item in queue" v-else :key="item.id" class="application-item" :class="{ selected: selected?.id === item.id }" @click="selected = item">
              <span class="store-avatar">{{ item.companyName.slice(0, 1) }}</span><span class="item-copy"><b>{{ item.companyName }}</b><small>{{ item.contactName }} · {{ item.contactEmail }}</small></span><em :data-status="item.status">{{ labels[item.status] }}</em>
            </button>
          </aside>

          <main class="review-detail">
            <div v-if="!selected" class="empty-state large"><span>⌁</span><b>选择一份申请开始审核</b><p>左侧展示全部申请及当前处理状态。</p></div>
            <template v-else>
              <div class="detail-title"><div class="store-avatar large">{{ selected.companyName.slice(0, 1) }}</div><div><span class="status-pill" :data-status="selected.status">{{ labels[selected.status] }}</span><h2>{{ selected.companyName }}</h2><p>申请编号 {{ selected.id.slice(-8).toUpperCase() }}</p></div></div>
              <div class="info-grid"><div><span>联系人</span><b>{{ selected.contactName }}</b><small>{{ selected.contactPhone }}</small></div><div><span>联系邮箱</span><b>{{ selected.contactEmail }}</b><small>主要业务联系人</small></div><div><span>营业执照号</span><b>{{ selected.businessLicenseNumber }}</b><small>待人工核验</small></div><div><span>资质材料</span><b>{{ selected.qualificationFileIds.length }} 份文件</b><small>私有加密存储</small></div></div>
              <section class="detail-section"><div class="section-heading"><div><span>HISTORY</span><h3>处理时间线</h3></div></div><ol class="audit-timeline"><li v-for="event in selected.timeline" :key="event.id"><i /><div><b>{{ labels[event.toStatus] }}</b><span>{{ new Date(event.createdAt).toLocaleString() }}</span><p v-if="event.comment">{{ event.comment }}</p></div></li></ol></section>
              <section class="detail-section decision"><div class="section-heading"><div><span>DECISION</span><h3>审核决策</h3></div></div><label><span>审核意见</span><textarea v-model="comment" rows="3" placeholder="记录判断依据；拒绝或补件时必须填写" /></label><div v-if="selected.status === 'SUBMITTED'" class="templates"><button v-for="reason in reasonTemplates" :key="reason" @click="comment = reason">＋ {{ reason }}</button></div><div v-if="selected.status === 'SUBMITTED'" class="actions"><button class="button secondary" :disabled="busy" @click="review('REQUEST_CHANGES')">要求补件</button><button class="button danger" :disabled="busy" @click="review('REJECT')">拒绝申请</button><button class="button primary" :disabled="busy" @click="review('APPROVE')">✓ 审核通过</button></div><div v-if="selected.status === 'APPROVED'" class="merchant-control"><div><span>当前营业状态</span><b :class="selected.merchantStatus === 'ACTIVE' ? 'online' : 'offline'"><i />{{ selected.merchantStatus === 'ACTIVE' ? '营业中' : '已停用' }}</b></div><button v-if="selected.merchantStatus === 'SUSPENDED'" class="button primary" @click="merchantStatus('ACTIVE')">恢复营业</button><button v-else class="button danger" @click="merchantStatus('SUSPENDED')">停用商家</button></div></section>
            </template>
          </main>
        </div>
      </template>

      <template v-else>
        <div v-if="mine" class="status-banner" :data-status="mine.status"><span class="status-icon">{{ mine.status === 'APPROVED' ? '✓' : 'i' }}</span><div><b>申请状态：{{ labels[mine.status] }}</b><p>{{ mine.reviewComment || (mine.status === 'SUBMITTED' ? '资料已进入审核队列，请耐心等待。' : mine.status === 'APPROVED' ? '恭喜，商家身份已经开通。' : '你可以继续完善资料后提交审核。') }}</p></div></div>
        <div class="applicant-layout">
          <form class="form-card" @submit.prevent="save">
            <div class="section-heading"><div><span>BUSINESS PROFILE</span><h2>经营主体信息</h2><p>请填写与资质文件一致的真实信息。</p></div><span class="required-note">* 必填</span></div>
            <div class="form-grid"><label><span>企业 / 工作室名称 *</span><input v-model="form.companyName" :disabled="!editable" required minlength="2" placeholder="例如：幻想工坊" /></label><label><span>营业执照号 *</span><input v-model="form.businessLicenseNumber" :disabled="!editable" required minlength="5" placeholder="统一社会信用代码或登记编号" /></label></div>
            <div class="divider" />
            <div class="section-heading compact"><div><span>CONTACT</span><h2>联系信息</h2></div></div>
            <div class="form-grid"><label><span>联系人 *</span><input v-model="form.contactName" :disabled="!editable" required minlength="2" placeholder="负责人姓名" /></label><label><span>联系电话 *</span><input v-model="form.contactPhone" :disabled="!editable" required minlength="6" placeholder="用于审核联络" /></label><label class="full"><span>联系邮箱 *</span><input v-model="form.contactEmail" :disabled="!editable" required type="email" placeholder="merchant@example.com" /></label></div>
            <div class="divider" />
            <div class="section-heading compact"><div><span>QUALIFICATIONS</span><h2>资质材料</h2><p>支持 JPG、PNG、WebP、PDF，最多 10 份。</p></div></div>
            <label class="upload-zone" :class="{ disabled: !editable }"><input :disabled="!editable" type="file" multiple accept="image/jpeg,image/png,image/webp,application/pdf" @change="addFiles(($event.target as HTMLInputElement).files)" /><span class="upload-icon">↥</span><b>{{ form.qualificationFileIds.length ? `已登记 ${form.qualificationFileIds.length} 份文件` : '点击选择或拖放资质文件' }}</b><small>单份文件信息将以私有方式保存</small></label>
            <label class="agreement"><input v-model="form.agreementAccepted" :disabled="!editable" type="checkbox" /><span>我已阅读并同意《MoeCraft 商家入驻协议》，承诺资料真实有效。</span></label>
            <div class="form-actions"><button v-if="editable" class="button secondary" :disabled="busy">保存草稿</button><button v-if="mine && ['DRAFT', 'NEEDS_CHANGES'].includes(mine.status)" type="button" class="button primary" :disabled="busy" @click="applicantAction('submit')">提交平台审核 →</button><button v-if="mine && ['DRAFT', 'SUBMITTED', 'NEEDS_CHANGES'].includes(mine.status)" type="button" class="text-button danger-text" :disabled="busy" @click="applicantAction('withdraw')">撤回申请</button></div>
          </form>

          <aside class="help-column"><section><span class="help-icon">◎</span><h3>审核需要多久？</h3><p>资料完整时通常在 1–3 个工作日内完成。审核结果会保留在处理时间线中。</p></section><section><span class="help-icon">◇</span><h3>资料安全</h3><p>资质材料为私有文件，仅授权审核人员可以访问，不会在商城公开展示。</p></section><section v-if="mine?.timeline.length" class="mini-timeline"><h3>申请进度</h3><ol><li v-for="event in mine.timeline" :key="event.id"><i /><div><b>{{ labels[event.toStatus] }}</b><small>{{ new Date(event.createdAt).toLocaleDateString() }}</small></div></li></ol></section></aside>
        </div>
      </template>
    </div>
  </section>
</template>

<style scoped>
.onboarding{--purple:#6957e8;--purple-dark:#5643d4;--purple-soft:#f0edff;color:var(--text);background:linear-gradient(145deg,var(--shell-bg),var(--surface-subtle));}.page-shell{width:min(1320px,100%);margin:0 auto}.hero{position:relative;display:flex;min-height:158px;align-items:center;justify-content:space-between;gap:30px;overflow:hidden;padding:30px 34px;margin-bottom:22px;border:1px solid color-mix(in srgb,var(--purple) 18%,var(--border));border-radius:18px;background:linear-gradient(112deg,color-mix(in srgb,var(--purple-soft) 80%,var(--surface)) 0%,var(--surface) 58%);box-shadow:0 16px 45px rgb(45 37 110 / 8%)}.hero::after{position:absolute;width:300px;height:300px;right:-95px;top:-155px;border:48px solid color-mix(in srgb,var(--purple) 8%,transparent);border-radius:50%;content:""}.hero-copy{position:relative;z-index:1;max-width:580px}.eyebrow{display:flex;align-items:center;gap:8px;color:var(--purple);font-size:11px;font-weight:700;letter-spacing:.16em}.eyebrow i{width:7px;height:7px;border-radius:50%;background:var(--purple);box-shadow:0 0 0 5px color-mix(in srgb,var(--purple) 12%,transparent)}h1{margin:10px 0 8px;color:var(--text);font-size:clamp(25px,3vw,38px);line-height:1.15;letter-spacing:-.035em}.hero p{max-width:560px;margin:0;color:var(--text-secondary);font-size:14px;line-height:1.7}.hero-steps{position:relative;z-index:1;display:flex;align-items:center;gap:10px}.hero-steps>span{display:grid;width:38px;height:38px;place-items:center;border:1px solid var(--border);border-radius:50%;background:var(--surface);color:var(--text-muted);font-weight:700}.hero-steps>span.done{border-color:var(--purple);background:var(--purple);color:white}.hero-steps>span small{position:absolute;margin-top:70px;color:var(--text-muted);font-size:11px;font-weight:500;white-space:nowrap}.hero-steps>i{width:54px;height:1px;background:var(--border)}.hero-metrics{position:relative;z-index:1;display:flex;gap:12px}.hero-metrics div{display:grid;min-width:96px;padding:14px 18px;border:1px solid var(--border);border-radius:12px;background:color-mix(in srgb,var(--surface) 82%,transparent);text-align:center}.hero-metrics b{color:var(--purple);font-size:25px}.hero-metrics span{color:var(--text-muted);font-size:11px}.icon-button{position:relative;z-index:2;display:grid;width:38px;height:38px;place-items:center;border:1px solid var(--border);border-radius:10px;background:var(--surface);color:var(--text-secondary);font-size:20px;cursor:pointer}.feedback{display:flex;align-items:center;gap:10px;padding:13px 16px;margin:0 0 18px;border:1px solid;border-radius:10px;font-size:13px}.feedback>span{display:grid;width:22px;height:22px;place-items:center;border-radius:50%;color:white}.is-error{border-color:color-mix(in srgb,var(--danger) 35%,var(--border));background:var(--danger-soft);color:var(--danger)}.is-error>span{background:var(--danger)}.is-success{border-color:color-mix(in srgb,var(--success) 35%,var(--border));background:var(--success-soft);color:var(--success)}.is-success>span{background:var(--success)}.loading-card,.empty-state{display:grid;min-height:220px;place-items:center;align-content:center;gap:10px;color:var(--text-muted);text-align:center}.spinner{width:30px;height:30px;border:3px solid var(--border);border-top-color:var(--purple);border-radius:50%;animation:spin .8s linear infinite}.status-banner{display:flex;align-items:center;gap:14px;padding:15px 18px;margin-bottom:18px;border:1px solid var(--border);border-left:4px solid var(--purple);border-radius:12px;background:var(--surface)}.status-banner[data-status="APPROVED"]{border-left-color:var(--success)}.status-banner[data-status="REJECTED"],.status-banner[data-status="NEEDS_CHANGES"]{border-left-color:var(--danger)}.status-icon{display:grid;width:34px;height:34px;place-items:center;border-radius:10px;background:var(--purple-soft);color:var(--purple);font-weight:700}.status-banner b{font-size:14px}.status-banner p{margin:4px 0 0;color:var(--text-muted);font-size:12px}.applicant-layout{displ